INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
('Frase.io', 'Frase.io', '营销', 'AI内容研究和写作工具，自动分析搜索意图、生成内容大纲，帮助快速创作SEO优化文章。', 'AI content research and writing tool analyzing search intent and generating SEO outlines.', '$14.99/月', 4.4, 'https://www.frase.io', ARRAY['搜索意图AI分析','内容大纲自动生成','SEO文章写作辅助','竞品内容对比'], true, false, false, 'frase-io', 'AI写作', 'AI搜索意图分析SEO文章写作', ARRAY['搜索意图分析准确','大纲生成实用','价格亲民'], ARRAY['深度写作需人工','主要面向英文内容'], 'SEO内容创作性价比最高的工具', ARRAY['热门','今日推荐'], 500, 'active');
INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
